func Test_CustomBaseUrl(t *testing.T) {
	// Client configured with a custom base URL routes all requests to that endpoint
	var request pkg.ChatCompletionRequest
	if err := json.Unmarshal([]byte(`{"messages":[{"content":"Hello","role":"user"}],"model":"local-model"}`), &request); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	mockURL := os.Getenv("MOCK_SERVER_URL") + "/fixtures/custom_base_url"
	client, clientErr := pkg.CreateClient("test-key", &mockURL, nil, nil, nil)
	if clientErr != nil {
		t.Fatalf("create client failed: %v", clientErr)
	}
	result, err := client.Chat(request)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var choices0MessageContent string
	if result.Choices[0].Message.Content != nil {
		choices0MessageContent = string(*result.Choices[0].Message.Content)
	}
	var choices0FinishReason string
	if result.Choices[0].FinishReason != nil {
		choices0FinishReason = string(*result.Choices[0].FinishReason)
	}
	assert.Equal(t, len(result.Choices), 1, "expected exactly 1 elements")
	if strings.TrimSpace(string(choices0MessageContent)) != `Hi there!` {
		t.Errorf("equals mismatch: got %v", choices0MessageContent)
	}
	if strings.TrimSpace(string(choices0FinishReason)) != `stop` {
		t.Errorf("equals mismatch: got %v", choices0FinishReason)
	}
	if strings.TrimSpace(string(result.Model)) != `local-model` {
		t.Errorf("equals mismatch: got %v", result.Model)
	}
}

